export const typedObjectEntries = obj => Object.entries(obj);
export const typedObjectFromEntries = entries => Object.fromEntries(entries);
export const typedObjectTransformValues = (obj, transform) => Object.fromEntries(Object.entries(obj).map(([key, value]) => [key, transform(value, key)]));
export const typedObjectKeys = obj => Object.keys(obj);
export const typedObjectValues = obj => Object.values(obj);
export function hasOwn(obj, key) {
  return Object.hasOwn(obj, key);
}
export function hasProp(obj, prop) {
  return typeof obj === 'object' && obj !== null && prop in obj;
}